var all_result = {};
first_gratuity_amt = 0;
second_gratuity_amt = 0;
$('#calculateBtn').click(function() {

   
    var hireDateStr = $('#hire_date').val();
    var parts = hireDateStr.split('/');
    var hireDate = new Date(parts[2], parts[1] - 1, parts[0]);
    var departureDate = new Date($('#departure_date').val());
    var contract_type = $('#contract_type').val();
    var reason = $('#reason').val();
    var basic_salary = $('#basic_salary').val();
    var gross_salary = $('#gross_salary').val();

    $('#error_message1').text('');
    $('#error_message2').text('');
    $('#error_message3').text('');

    if (!departureDate || isNaN(departureDate.getTime())) {
        $('#total_service_duration').val('');
        $('#error_message1').text('Please enter a valid departure date.');
    }

    if (!contract_type) {
        $('#error_message2').text('Please enter the contract type.');
    }

    if (!reason) {
        $('#error_message3').text('Please enter the reason.');
    }

    if ($('#error_message1').text() || $('#error_message2').text() || $('#error_message3').text()) {
        return;
    }

    var timeDifference = departureDate - hireDate;
    // var user_absent_count = $('#user_absent_days').val();
    var absent_count = $('#absent_days').val();

    var daysDifference = Math.floor(timeDifference / (1000 * 60 * 60 * 24)) + 1;
    daysDifference = daysDifference - absent_count;
    var monthsDifference = (daysDifference / (365 / 12)).toFixed(5);
    var yearsDifference = (monthsDifference / 12).toFixed(3);
    // Gratuity Calculations
    var first_gratuity = 0.00;
    var second_gratuity = 0.00;
    if(daysDifference > 365) {
        // $('#error_message1').text('The difference between hire date and departure date must be at least one year.');
        // return;
        switch (true) {
            case yearsDifference <= 5:
                first_gratuity = (basic_salary / 30 * 21 * yearsDifference).toFixed(2);
                break;

            case yearsDifference > 5:
                first_gratuity = (basic_salary / 30 * 21 * 5).toFixed(2);
                var remaning_years = yearsDifference - 5;
                second_gratuity = (basic_salary / 30 * 30 * remaning_years).toFixed(2);
                break;
        }
    }
    console.log('Years Difference:', yearsDifference);
    console.log(first_gratuity);
    console.log(basic_salary);

    var absent_days = $('#absent_days').val();
    var user_id = userId;

    $.ajax({
        url: storeAbsentDaysUrl,
        method: "POST",
        headers: {
            'X-CSRF-TOKEN': $('meta[name="csrf-token"]').attr('content')
        },
        data: {
            absent_days: absent_days,
            user_id: user_id
        },
        success: function(response) {
            if(response.success==true){
                // alert('Data saved successfully!');
            } else {
                // alert('Something went wrong.');
            }
        },
        error: function(xhr) {
            //alert('Error: ' + xhr.responseText);
        }
    });

    var total_leave_amount = 0; var total_calculated_amount = 0; var total_salary_amount = 0;
    var total_additions = 0; var total_deductions = 0;
    $.ajax({url: getResponseAPI, success: function(result){
        var additions = result.extraPara.total_additions;
        var deductions = result.extraPara.total_deductions;
        $('#loaderModal').modal('show');
        setTimeout(function() {
            $('#loaderModal').modal('hide');
        }, 5000);
        var ajaxCalls = [];
        if (result.leave_name && result.leave_name.trim() !== '') {
            var leaveNames = result.leave_name.split(',');

            // Loop over each leave name from the saved string
            leaveNames.forEach(function (leaveName) {
                // Trim to remove extra spaces
                leaveName = leaveName.trim();

                // Find the leave object in result.data
                var leave = result.data.find(function (item) {
                    return item.name === leaveName;
                });

                if (leave) {
                    var leave_amount = 0;
                    // if(leaveName === 'Vacation') {
                    //     if (basic_salary !== 'Not Set') {
                    //         leave_amount = ((basic_salary / 30) * leave.balance).toFixed(2);
                    //     }
                    // } else {
                    //     if (gross_salary !== 'Not Set') {
                    //         leave_amount = ((gross_salary / 30) * leave.balance).toFixed(2);
                    //     }
                    // }
                    let leave_type_id = null;
                    const item = result.data.find(function (item) {
                        return item.name === leaveName;
                    });
                    
                    if (item) {
                        leave_type_id = item.type_id;
                    }

                    var promise = $.ajax({
                        url: getpolicyUrl,
                        type: 'POST',
                        data: {
                            _token: $('meta[name="csrf-token"]').attr('content'),
                            leave_type_id: leave_type_id,
                            user_id: userId
                        }
                    }).then(function (response) {
                        let monthday = 30;
                        let salaryType = gross_salary;
                        if (response.data && response.data.spolicy.id) {
                            monthday = response.data.spolicy.month_day;
                            salaryType = (response.data.spolicy.salary_type === 'Basic') ? basic_salary : gross_salary;
                        }
            
                        let leave_amount = ((salaryType / monthday) * leave.balance).toFixed(2);
                        total_leave_amount = parseFloat(total_leave_amount) + parseFloat(leave_amount);
            
                        var newRow = $("<tr>");
                        newRow.append("<td><input type='text' value='" + leave.name + "' class='leave-name' style='display: none;' />" + leave.name + "</td>");
                        newRow.append("<td>" + leave.balance + " Days</td>");
                        newRow.append("<td><input type='number' value='" + leave_amount + "' class='leave-sum' /></td>");
                        
                        if (leave.balance > 0) {
                            $("#leaveTable tr:contains('Leave encashments')").after(newRow);
                        }
            
                    }).fail(function (xhr) {
                        console.error('Error fetching leave policy:', xhr);
                    });
                    ajaxCalls.push(promise);
                }
            });
        }
        // for salary
        var promise = $.ajax({
            url: getsalaryUrl,
            type: 'POST',
            data: {
                _token: $('meta[name="csrf-token"]').attr('content'),
                user_id: userId
            }
        }).then(function (response) {
            if(response.data !== null) {
                if (response.data.settlementSalary > 0) {
                    total_salary_amount = parseFloat(total_salary_amount) + parseFloat(response.data.settlementSalary);
                    const monthNumbers = response.data.off.salary_month.split(',');
                    const monthNames = [
                        "January", "February", "March", "April", "May", "June",
                        "July", "August", "September", "October", "November", "December"
                    ];

                    const readableMonths = monthNumbers.map(m => {
                        const index = parseInt(m.trim()) - 1;
                        return monthNames[index] || '';
                    }).filter(Boolean).join(', ');

                    const newsalaryRow = $("<tr class='row-final-salary'>");
                    newsalaryRow.append("<td><input type='text' class='month-name' style='display: none;' /> Final Salary </td>");
                    newsalaryRow.append("<td>" + readableMonths + " Months (" + response.data.working_day +") working day</td>");
                    newsalaryRow.append("<td><input type='number' value='" + response.data.settlementSalary + "'disabled class='settlementSalary-sum' /></td>");
                    $("#leaveTable #salaryRow").after(newsalaryRow);

                    // const gross_salaryRow = $("<tr class='row-gross-salary'>");
                    // gross_salaryRow.append("<td><input type='text' class='month-name' style='display: none;' /> Gross Salary </td>");
                    // gross_salaryRow.append("<td>-</td>");
                    // gross_salaryRow.append("<td><input type='number' value='" + response.data.gross_salary + "'disabled class='gross_salary-sum' /></td>");
                    // $("#leaveTable #salaryRow").after(gross_salaryRow);

                    const total_deductionRow = $("<tr class='row-total-deduction'>");
                    total_deductionRow.append("<td><input type='text' class='month-name' style='display: none;' /> Total Deduction (not fix deduction) </td>");
                    total_deductionRow.append("<td>-</td>");
                    total_deductionRow.append("<td><input type='number' value='" + response.data.total_deduction + "'disabled class='total_deduction-sum' /></td>");
                    $("#leaveTable #salaryRow").after(total_deductionRow);

                    const overtime_amountRow = $("<tr class='row-overtime-amount'>");
                    overtime_amountRow.append("<td><input type='text' class='month-name' style='display: none;' /> Total Overtime Amount </td>");
                    overtime_amountRow.append("<td>+</td>");
                    overtime_amountRow.append("<td><input type='number' value='" + response.data.overtime_amount + "'disabled class='overtime_amount-sum' /></td>");
                    $("#leaveTable #salaryRow").after(overtime_amountRow);

                    const monthly_expenseRow = $("<tr class='row-monthly-expense'>");
                    monthly_expenseRow.append("<td><input type='text' class='month-name' style='display: none;' /> Total Monthly Expense </td>");
                    monthly_expenseRow.append("<td>+</td>");
                    monthly_expenseRow.append("<td><input type='number' value='" + response.data.monthly_expense + "'disabled class='monthly_expense-sum' /></td>");
                    $("#leaveTable #salaryRow").after(monthly_expenseRow);

                } else {
                    // const newsalaryRow = $("<tr>");
                    // newsalaryRow.append("<td><input type='text' class='month-name' style='display: none;' /> Final Salary </td>");
                    // newsalaryRow.append("<td>" + response.data.off.salary_month + " Months</td>");
                    // newsalaryRow.append("<td><input type='number' value='" + 0 + "'disabled class='settlementSalary-sum' /></td>");
                    // $("#leaveTable #salaryRow").after(newsalaryRow);
                }
            }
        }).fail(function (xhr) {
            console.error('Error fetching leave policy:', xhr);
        });
        ajaxCalls.push(promise);
        // end

        $.when.apply($, ajaxCalls).then(function () {

            if(result.addition_list && result.addition_list.length > 0){
                result.addition_list.forEach(function (addition, index) {
                    if(addition.percentage_amount != 0){
                        addition.amount = addition.percentage_amount;
                    }
                    total_additions = parseFloat(total_additions) + parseFloat(addition.amount);
                    var newRow = $("<tr>");
                    newRow.append("<td></td>");
                    newRow.append("<td>" + addition.title + "</td>");
                    newRow.append("<td><input type='number' value='" + addition.amount + "' class='addition-sum' /></td>");
                    $("#leaveTable tr:contains('Addition List')").after(newRow);
                });
            } else {
                total_additions = result.additions;
                var newRow = $("<tr>");
                    newRow.append("<td></td>");
                    newRow.append("<td></td>");
                    newRow.append("<td><input type='number' value='" + result.additions + "' class='addition-sum' /></td>");
                    $("#leaveTable tr:contains('Addition List')").after(newRow);
            }
            if(result.deduction_list && result.deduction_list.length > 0){
                result.deduction_list.forEach(function (deduction, index) {
                    if(deduction.percentage_amount != 0){
                        deduction.amount = deduction.percentage_amount;
                    }
                    total_deductions = parseFloat(total_deductions) + parseFloat(deduction.amount);
                    var newRow = $("<tr>");
                    newRow.append("<td></td>");
                    newRow.append("<td>" + deduction.title + "</td>");
                    newRow.append("<td><input type='number' value='" + deduction.amount + "' class='deduction-sum' /></td>");
                    $("#leaveTable tr:contains('Deduction List')").after(newRow);
                });
            } else {
                total_deductions = result.deductions;
                var newRow = $("<tr>");
                    newRow.append("<td></td>");
                    newRow.append("<td></td>");
                    newRow.append("<td><input type='number' value='" + result.deductions + "' class='deduction-sum' /></td>");
                    $("#leaveTable tr:contains('Deduction List')").after(newRow);
            }
            
            $('#total_additions').text(additions);
            $('#total_deductions').text(deductions);
            total_calculated_amount = parseFloat(first_gratuity) + parseFloat(second_gratuity) + parseFloat(total_leave_amount) + parseFloat(total_salary_amount) + parseFloat(total_additions) - parseFloat(total_deductions);
            total_calculated_amount = total_calculated_amount.toFixed(2);
            first_gratuity_amt = parseFloat(first_gratuity);
            second_gratuity_amt = parseFloat(second_gratuity);
            displayPopup();
        });
    }});

    function displayPopup() {

        $('#error_message').text('');        
        $('#total_service_duration').val(yearsDifference + ' years, ' + monthsDifference + ' months, ' +
            daysDifference + ' days');
        $('#first_gratuity').text(first_gratuity);
        $('#second_gratuity').text(second_gratuity);
        $('#total_amount').text(total_calculated_amount);
        all_result = {
            'hire_date': $('#hire_date').val(),
            'departure_date': $('#departure_date').val(),
            'contract_type': $('#contract_type').val(),
            'departure_reason_id': $('#reason').val(),
            'total_service_duration': yearsDifference + ' years',
            'settlement_amount': total_calculated_amount
            };
        $('#finalSettlement').css('display', 'block');
        $('html, body').animate({
            scrollTop: $('#finalSettlement').offset().top
        }, 500);
    }
});

    $('#leaveTable').on('input', '.leave-sum, .addition-sum, .deduction-sum', function () {
        recalculateOnInput();
    });

    function recalculateOnInput() {
        var newTotalLeaveAmount = 0;
        var newTotalSalaryAmount = 0;

        $('.leave-sum').each(function () {
            newTotalLeaveAmount += parseFloat($(this).val()) || 0;
        });

        newTotalSalaryAmount += parseFloat($('.settlementSalary-sum').val()) || 0;

        var newTotalAdditions = 0;
        $('.addition-sum').each(function () {
            newTotalAdditions += parseFloat($(this).val()) || 0;
        });

        var newTotalDeductions = 0;
        $('.deduction-sum').each(function () {
            newTotalDeductions += parseFloat($(this).val()) || 0;
        });

        var newTotalCalculatedAmount = first_gratuity_amt + second_gratuity_amt +
            parseFloat(newTotalLeaveAmount) + parseFloat(newTotalSalaryAmount) + parseFloat(newTotalAdditions) - parseFloat(newTotalDeductions);

        newTotalCalculatedAmount = newTotalCalculatedAmount.toFixed(2);

        $('#total_leave_amount').text(newTotalLeaveAmount.toFixed(2));
        $('#total_additions').text(newTotalAdditions.toFixed(2));
        $('#total_deductions').text(newTotalDeductions.toFixed(2));
        $('#total_amount').text(newTotalCalculatedAmount);

        all_result.total_leave_amount = newTotalLeaveAmount.toFixed(2);
        all_result.newTotalSalaryAmount = newTotalSalaryAmount.toFixed(2);
        all_result.total_additions = newTotalAdditions.toFixed(2);
        all_result.total_deductions = newTotalDeductions.toFixed(2);
        all_result.settlement_amount = newTotalCalculatedAmount;
    }


    function submitReviewForm(){
        var newTotalCalculatedAmount = $('#total_amount').text().replace(/[^0-9.]/g, '');
        if (typeof all_result === 'undefined') {
            console.error('all_result is not defined.');
            return;
        }
        all_result.settlement_amount = parseFloat(newTotalCalculatedAmount);

        // 2. Collect all leave names
        var leaveNames = [];

        $('.leave-name').each(function () {
            var name = $(this).val(); // or .text() if you're using inner text
            if (name) {
                leaveNames.push(name.trim());
            }
        });

        // 3. Convert to comma-separated string
        all_result.leave_names = leaveNames.join(',');

        $.ajax({
            url: settlementSubmitAPI,
            method: 'POST',
            data: {
                all_result: all_result,
            },
            success: function (response) {
                if (response.success) {
                    if (response.message) {
                        showAlert(response.message, "success");
                    }
                    location.reload();
                } else {
                    showAlert(response.message, "error");
                }
            },
            error: function (e) {
                if (showFormError) {
                    showFormError(e, form);
                } else {
                    console.error('AJAX request failed', e);
                }
            }
        });
    }
